import React from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { useAppContext } from '../context/AppContext';
import StatCard from '../components/StatCard';
import HistoryList from '../components/HistoryList';

export default function Dashboard() {
  const navigate = useNavigate();
  const { predictionHistory, chatHistory, restorePrediction, restoreChat } = useAppContext();

  const recentActivity = [
    ...predictionHistory.slice(0, 3).map((item) => ({
      id: item.id,
      title: item.breedName,
      subtitle: 'Prediction',
      createdAt: item.createdAt,
      action: () => restorePrediction(item),
      path: '/classifier',
    })),
    ...chatHistory.slice(0, 3).map((item) => ({
      id: item.id,
      title: item.title,
      subtitle: 'Chat',
      createdAt: item.createdAt,
      action: () => restoreChat(item),
      path: '/chat',
    })),
  ]
    .sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt))
    .slice(0, 5);

  return (
    <div className="dashboard-page">
      <div className="dashboard-grid">
        <div className="dashboard-panel">
          <div className="panel-header">
            <p className="panel-label">Overview</p>
            <h2>Activity at a glance</h2>
          </div>

          <div className="stat-grid">
            <StatCard label="Total predictions" value={predictionHistory.length} note="Saved in local history" />
            <StatCard label="Chat sessions" value={chatHistory.length} note="Recent conversations" />
            <StatCard label="Available pages" value="4" note="Classifier, Chat, About, Dashboard" />
          </div>

          <div className="quick-actions">
            <p className="section-heading">Quick actions</p>
            <div className="button-row">
              <button type="button" className="secondary-button" onClick={() => navigate('/classifier')}>
                Run classifier
              </button>
              <button type="button" className="secondary-button" onClick={() => navigate('/chat')}>
                Open chat
              </button>
            </div>
          </div>
        </div>

        <motion.div
          className="dashboard-panel recent-panel"
          initial={{ opacity: 0, y: 14 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.35 }}
        >
          <div className="panel-header">
            <p className="panel-label">Recent activity</p>
            <h2>Latest entries</h2>
          </div>

          {recentActivity.length ? (
            <div className="activity-list">
              {recentActivity.map((item) => (
                <button
                  type="button"
                  key={item.id}
                  className="activity-item"
                  onClick={() => {
                    item.action();
                    navigate(item.path);
                  }}
                >
                  <div>
                    <p className="activity-title">{item.title}</p>
                    <span className="activity-type">{item.subtitle}</span>
                  </div>
                  <span className="activity-time">{new Date(item.createdAt).toLocaleDateString()}</span>
                </button>
              ))}
            </div>
          ) : (
            <div className="empty-state">No activity yet. Start by uploading an image or sending a chat message.</div>
          )}
        </motion.div>
      </div>

      <div className="dashboard-bottom">
        <HistoryList
          title="Prediction history"
          items={predictionHistory.map((item) => ({
            ...item,
            title: item.breedName,
          }))}
          renderItem={(item) => {
            restorePrediction(item);
            navigate('/classifier');
          }}
          emptyText="No saved predictions yet"
        />

        <HistoryList
          title="Chat history"
          items={chatHistory.map((item) => ({
            ...item,
            title: item.title,
          }))}
          renderItem={(item) => {
            restoreChat(item);
            navigate('/chat');
          }}
          emptyText="No chat sessions yet"
        />
      </div>
    </div>
  );
}
